 1→// Example 17: Functions that branch on mock return values.
 2→// Tests dynamic mock discovery — the concolic explorer should generate varied
 3→// mock return values per iteration to discover all branches gated by external
 4→// dependency behavior.
 5→//
 6→// Each function imports an external module (fs) so the analyzer detects
 7→// external dependencies. The branches are controlled by mock return values,
 8→// not by direct parameters alone.
 9→
10→import * as fs from "fs";
11→
12→// ── HTTP-like status branching ─────────────────────────────────────────
13→//
14→// Simulates a function that reads a file and branches on its content,
15→// which acts as a "status" from an external source.
16→//
17→// EXPECTED BRANCHES (4):
18→//   1. status === "200"   → "ok"
19→//   2. status === "404"   → "not-found"
20→//   3. status === "500"   → "server-error"
21→//   4. default            → "unknown:<status>"
22→//
23→// MOCKS: fs.readFileSync returns the status string.
24→// Dynamic mocking should vary the readFileSync return value to discover all 4 branches.
25→export function classifyStatus(configPath: string): string {
26→    const status = fs.readFileSync(configPath, "utf-8").trim();
27→
28→    if (status === "200") {
29→        return "ok";
30→    }
31→    if (status === "404") {
32→        return "not-found";
33→    }
34→    if (status === "500") {
35→        return "server-error";
36→    }
37→    return `unknown:${status}`;
38→}
39→
40→// ── Result/Error branching ─────────────────────────────────────────────
41→//
42→// Reads a config file; branches on whether the read succeeds or throws,
43→// and on the content when it succeeds.
44→//
45→// EXPECTED BRANCHES (3):
46→//   1. fs.existsSync returns false  → "missing"
47→//   2. file exists, content empty   → "empty-config"
48→//   3. file exists, content present → "loaded:<length>"
49→//
50→// MOCKS: fs.existsSync → true/false, fs.readFileSync → string content.
51→// Dynamic mocking should vary both mock return values.
52→export function loadOrDefault(filePath: string): string {
53→    if (!fs.existsSync(filePath)) {
54→        return "missing";
55→    }
56→
57→    const content = fs.readFileSync(filePath, "utf-8");
58→    if (content.length === 0) {
59→        return "empty-config";
60→    }
61→
62→    return `loaded:${content.length}`;
63→}
64→
65→// ── Loop with mock-per-iteration ───────────────────────────────────────
66→//
67→// Reads multiple config files in a loop. Each iteration calls readFileSync,
68→// and the branch depends on whether the content starts with "#".
69→//
70→// EXPECTED BRANCHES (3):
71→//   1. all files start with "#"    → "all-comments"
72→//   2. no files start with "#"     → "no-comments"
73→//   3. mixed                       → "mixed"
74→//
75→// MOCKS: fs.readFileSync returns different content per call.
76→// Dynamic mocking cycles through return_values, so varied values per call
77→// produce different branch outcomes.
78→export function classifyConfigs(paths: string[]): string {
79→    if (paths.length === 0) {
80→        return "no-comments";
81→    }
82→
83→    let commentCount = 0;
84→    for (const p of paths) {
85→        const content = fs.readFileSync(p, "utf-8");
86→        if (content.startsWith("#")) {
87→            commentCount++;
88→        }
89→    }
90→
91→    if (commentCount === paths.length) {
92→        return "all-comments";
93→    }
94→    if (commentCount === 0) {
95→        return "no-comments";
96→    }
97→    return "mixed";
98→}
