pub fn mutate_mock_values(
    configs: &[MockConfig],
    mock_params: &[MockParam],
    mutation_rate: f64,
    dictionary: &[&str],
    rng: &mut impl Rng,
) -> Vec<MockConfig> {
    configs
        .iter()
        .zip(mock_params.iter())
        .map(|(config, mp)| {
            let return_values = config
                .return_values
                .iter()
                .map(|val| {
                    if rng.random_range(0.0..1.0_f64) < mutation_rate {
                        mutate_value(val, &mp.return_type, dictionary, rng)
                    } else {
                        val.clone()
                    }
                })

